import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];
        int length = input.length();

        if (length <= buffer.length) {
            input.getChars(0, length, buffer, 0);
            System.out.println("Buffer content: " + new String(buffer));
        } else {
            // Handle input that exceeds buffer size
            char[] safeBuffer = Arrays.copyOf(input.toCharArray(), buffer.length);
            System.out.println("Buffer content: " + new String(safeBuffer));
            System.out.println("Input string was truncated to fit the buffer size.");
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
